const feeds = [
  { name: 'TechCrunch AI', url: 'https://techcrunch.com/category/artificial-intelligence/feed/' },
  { name: 'Anthropic Blog', url: 'https://www.anthropic.com/news/rss.xml' },
  { name: 'OpenAI Blog', url: 'https://openai.com/blog/rss.xml' }
];
const FALLBACK_FEED = { name: 'The Verge AI', url: 'https://www.theverge.com/ai-artificial-intelligence/rss/index.xml' };
function parseRSS(xml) {
  const items = [];
  const itemMatches = xml.matchAll(/<item[^>]*>([\s\S]*?)<\/item>/gi);
  for (const match of itemMatches) {
    const block = match[1];
    const getTag = (tag) => {
      const m = block.match(new RegExp(`<${tag}[^>]*><!\\[CDATA\\[([\\s\\S]*?)\\]\\]><\/${tag}>`, 'i')) || block.match(new RegExp(`<${tag}[^>]*>([\\s\\S]*?)<\/${tag}>`, 'i'));
      return m ? m[1].trim() : '';
    };
    items.push({ title: getTag('title'), summary: getTag('description').replace(/<[^>]+>/g, '').substring(0, 300), source_url: getTag('link') });
  }
  return items.slice(0, 5);
}
async function fetchFeed(url, timeoutMs = 8000) {
  const controller = new AbortController();
  const timer = setTimeout(() => controller.abort(), timeoutMs);
  try {
    const res = await fetch(url, { signal: controller.signal });
    if (!res.ok) throw new Error(`HTTP ${res.status}`);
    return await res.text();
  } finally { clearTimeout(timer); }
}
const allItems = [];
const errors = [];
for (const feed of feeds) {
  let xml;
  try { xml = await fetchFeed(feed.url); }
  catch (err) {
    errors.push(`${feed.name} failed, using fallback.`);
    try { xml = await fetchFeed(FALLBACK_FEED.url); feed.name = FALLBACK_FEED.name; }
    catch (e) { errors.push(`Fallback failed: ${e.message}`); continue; }
  }
  for (const item of parseRSS(xml)) allItems.push({ ...item, feed: feed.name });
}
return [{ json: { stories: allItems, errors } }];

const raw = $input.first().json;
const content = raw.content?.[0]?.text || raw.content || '';
let stories;
try {
  const cleaned = content.replace(/```json/gi, '').replace(/```/g, '').trim();
  stories = JSON.parse(cleaned);
} catch (e) { throw new Error('Failed to parse Claude story picker response: ' + content); }
if (!Array.isArray(stories) || stories.length === 0) throw new Error('Expected a JSON array of stories from Claude.');
return stories.map((story, i) => ({ json: { ...story, story_index: i + 1 } }));

const fs = require('fs');
const voiceFile = '/data/scripts/abdul-rahman-voice.txt';
let voicePrompt = '';
try { voicePrompt = fs.readFileSync(voiceFile, 'utf8'); }
catch (e) { voicePrompt = 'You are writing Instagram carousel content for Abdul Rahman. Short, punchy sentences. Direct. No fluff. Bold, practical, no-nonsense tone. Never use: In today world, Game-changer, Leverage.'; }
const item = $input.first().json;
return [{ json: { ...item, voicePrompt } }];

const items = $input.all();
const carousels = [];
for (const item of items) {
  const raw = item.json;
  const content = raw.content?.[0]?.text || raw.content || '';
  let slides;
  try {
    const cleaned = content.replace(/```json/gi, '').replace(/```/g, '').trim();
    slides = JSON.parse(cleaned);
  } catch (e) { throw new Error(`Failed to parse slide script: ${content.substring(0, 200)}`); }
  carousels.push({ title: item.json.title || 'Story', source_url: item.json.source_url || '', slides });
}
return [{ json: { carousels } }];

const fs = require('fs');
const carousels = $input.first().json.carousels || [];
const outputData = { carousels };
const pendingFile = '/data/scripts/pending-insta.json';
try {
  fs.writeFileSync(pendingFile, JSON.stringify(outputData), 'utf8');
} catch (err) {
  throw new Error('Failed to write trigger file: ' + err.message);
}
return [{ json: { status: 'dispatched', file: pendingFile, count: carousels.length } }];
